// Obtém os dados do webhook
const data = $input.first().json.body;

// Função para escapar HTML
function escapeHtml(str) {
  if (!str) return '';
  return str
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#39;');
}

// Constrói o HTML dinamicamente
let containersHtml = '';
const containers = data.containers || [];

if (containers.length === 0) {
  containersHtml = '<p style="text-align: center; color: #999; font-style: italic; margin-top: 16px;">Nenhum container Docker em execução</p>';
} else {
  containersHtml = `
    <table style="width: 100%; border-collapse: collapse; font-size: 14px;">
      <thead>
        <tr style="background-color: #f8f9fa;">
          <th style="padding: 10px; text-align: left; border-bottom: 2px solid #dee2e6;">Container</th>
          <th style="padding: 10px; text-align: center; border-bottom: 2px solid #dee2e6;">Status</th>
          <th style="padding: 10px; text-align: left; border-bottom: 2px solid #dee2e6;">Imagem</th>
        </tr>
      </thead>
      <tbody>
  `;
  for (const container of containers) {
    const badge = container.update_available
      ? '<span style="background-color: #ff9800; color: white; padding: 2px 8px; border-radius: 12px; font-size: 11px; font-weight: bold;">🔄 UPDATE</span>'
      : '<span style="background-color: #4caf50; color: white; padding: 2px 8px; border-radius: 12px; font-size: 11px; font-weight: bold;">✓ OK</span>';
    containersHtml += `
      <tr>
        <td style="padding: 8px 0; border-bottom: 1px solid #f0f0f0;"><strong>${escapeHtml(container.name)}</strong></td>
        <td style="padding: 8px 0; border-bottom: 1px solid #f0f0f0; text-align: center;">${badge}</td>
        <td style="padding: 8px 0; border-bottom: 1px solid #f0f0f0; font-family: monospace; font-size: 12px;">${escapeHtml(container.image)}</td>
      </tr>
    `;
  }
  containersHtml += '</tbody></table>';
}

const htmlContent = `
<div style="font-family: Arial, sans-serif; max-width: 600px; margin: 0 auto; border: 1px solid #e0e0e0; border-radius: 8px; overflow: hidden; color: #333333;">
  <div style="background-color: #2c3e50; color: #ffffff; padding: 20px; text-align: center;">
    <h2 style="margin: 0; font-size: 20px;">Relatório de Saúde da Infraestrutura</h2>
  </div>
  <div style="padding: 24px;">
    <div style="background-color: #f8f9fa; padding: 15px; border-radius: 6px; border-left: 4px solid #27ae60; margin-bottom: 24px;">
      <p style="margin: 0 0 8px 0;"><strong>Status Geral:</strong> ${escapeHtml(data.status_global)}</p>
      <p style="margin: 0;"><strong>Uptime:</strong> ${escapeHtml(data.sistema.uptime)}</p>
    </div>
    <h3 style="color: #2980b9; margin-bottom: 12px; font-size: 16px; border-bottom: 1px solid #eeeeee; padding-bottom: 6px;">💾 SDCARD</h3>
    <table style="width: 100%; border-collapse: collapse; margin-bottom: 24px; font-size: 14px;">
      <tr><td style="padding: 8px 0; border-bottom: 1px solid #f0f0f0;"><strong>Status:</strong></td><td style="padding: 8px 0; border-bottom: 1px solid #f0f0f0; text-align: right;">${escapeHtml(data.sd_card.status)}</td></tr>
      <tr><td style="padding: 8px 0; border-bottom: 1px solid #f0f0f0;"><strong>Detalhe:</strong></td><td style="padding: 8px 0; border-bottom: 1px solid #f0f0f0; text-align: right;">${escapeHtml(data.sd_card.mensagem)}</td></tr>
      <tr><td style="padding: 8px 0;"><strong>Uso do HD:</strong></td><td style="padding: 8px 0; text-align: right;">${escapeHtml(data.sd_card.uso_pct)}%</td></tr>
    </table>
    <h3 style="color: #2980b9; margin-bottom: 12px; font-size: 16px; border-bottom: 1px solid #eeeeee; padding-bottom: 6px;">💾 HD EXTRENO</h3>
    <table style="width: 100%; border-collapse: collapse; margin-bottom: 24px; font-size: 14px;">
      <tr><td style="padding: 8px 0; border-bottom: 1px solid #f0f0f0;"><strong>Status:</strong></td><td style="padding: 8px 0; border-bottom: 1px solid #f0f0f0; text-align: right;">${escapeHtml(data.disco.status)}</td></tr>
      <tr><td style="padding: 8px 0; border-bottom: 1px solid #f0f0f0;"><strong>Detalhe:</strong></td><td style="padding: 8px 0; border-bottom: 1px solid #f0f0f0; text-align: right;">${escapeHtml(data.disco.mensagem)}</td></tr>
      <tr><td style="padding: 8px 0;"><strong>Uso do HD:</strong></td><td style="padding: 8px 0; text-align: right;">${escapeHtml(data.disco.uso_pct)}%</td></tr>
    </table>
    <h3 style="color: #2980b9; margin-bottom: 12px; font-size: 16px; border-bottom: 1px solid #eeeeee; padding-bottom: 6px;">🧠 MEMÓRIA</h3>
    <table style="width: 100%; border-collapse: collapse; margin-bottom: 24px; font-size: 14px;">
      <tr><td style="padding: 8px 0; border-bottom: 1px solid #f0f0f0;"><strong>Uso de RAM:</strong></td><td style="padding: 8px 0; border-bottom: 1px solid #f0f0f0; text-align: right;">${escapeHtml(data.memoria.uso_pct)}%</td></tr>
      <tr><td style="padding: 8px 0;"><strong>Consumo Absoluto:</strong></td><td style="padding: 8px 0; text-align: right;">${escapeHtml(data.memoria.usada_mb)} MB</td></tr>
    </table>
    <h3 style="color: #2980b9; margin-bottom: 12px; font-size: 16px; border-bottom: 1px solid #eeeeee; padding-bottom: 6px;">⚙️ CPU</h3>
    <table style="width: 100%; border-collapse: collapse; margin-bottom: 24px; font-size: 14px;">
      <tr><td style="padding: 8px 0; border-bottom: 1px solid #f0f0f0;"><strong>Temperatura:</strong></td><td style="padding: 8px 0; border-bottom: 1px solid #f0f0f0; text-align: right;">${escapeHtml(data.cpu.temperatura_c)} °C</td></tr>
      <tr><td style="padding: 8px 0;"><strong>Carga (1m):</strong></td><td style="padding: 8px 0; text-align: right;">${escapeHtml(data.cpu.load_1m)}</td></tr>
    </table>
    <h3 style="color: #2980b9; margin-bottom: 12px; font-size: 16px; border-bottom: 1px solid #eeeeee; padding-bottom: 6px;">🐳 CONTAINERS EM EXECUÇÃO</h3>
    ${containersHtml}
  </div>
  <div style="background-color: #f4f4f4; padding: 12px; text-align: center; font-size: 11px; color: #888888;">
    Relatório gerado automaticamente pelo sistema de monitoramento via n8n.
  </div>
</div>
`;

// Define o assunto com ícone
let icon = '';
if (data.status_global === 'OK') icon = '🟢';
else if (data.status_global === 'WARNING') icon = '🟡';
else icon = '🔴';
const subject = `${icon} Relatório do Servidor: ${data.status_global}`;

// Retorna o HTML e o assunto para o próximo nó
return {
  html: htmlContent,
  subject: subject,
  // Mantém os dados originais se necessário
  ...$input.first().json
};
